import (
	"container/heap"
)

type IntHeap []int64

func (h IntHeap) Len() int           { return len(h) }
func (h IntHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h IntHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *IntHeap) Push(x interface{}) {
	*h = append(*h, x.(int64))
}

func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	cInt := int(c)
	graph := make([][]int64, cInt+1)
	for i := range graph {
		graph[i] = []int64{}
	}

	for _, conn := range connections {
		u, v := conn[0], conn[1]
		uInt := int(u)
		vInt := int(v)
		graph[uInt] = append(graph[uInt], v)
		graph[vInt] = append(graph[vInt], u)
	}

	visited := make([]bool, cInt+1)
	compIdArray := make([]int64, cInt+1)
	compHeapMap := make(map[int64]*IntHeap)
	compCounter := int64(0)

	for i := 1; i <= cInt; i++ {
		if !visited[i] {
			queue := []int64{int64(i)}
			visited[i] = true
			compNodes := []int64{int64(i)}
			for len(queue) > 0 {
				node := queue[0]
				queue = queue[1:]
				nodeInt := int(node)
				for _, neighbor := range graph[nodeInt] {
					neighborInt := int(neighbor)
					if !visited[neighborInt] {
						visited[neighborInt] = true
						queue = append(queue, neighbor)
						compNodes = append(compNodes, neighbor)
					}
				}
			}
			h := make(IntHeap, len(compNodes))
			copy(h, compNodes)
			heap.Init(&h)
			compHeapMap[compCounter] = &h
			for _, node := range compNodes {
				nodeInt := int(node)
				compIdArray[nodeInt] = compCounter
			}
			compCounter++
		}
	}

	onlineArr := make([]bool, cInt+1)
	for i := 1; i <= cInt; i++ {
		onlineArr[i] = true
	}

	ans := []int64{}
	for _, q := range queries {
		typ, x := q[0], q[1]
		xInt := int(x)
		if typ == 1 {
			if onlineArr[xInt] {
				ans = append(ans, x)
			} else {
				compId := compIdArray[xInt]
				hPtr := compHeapMap[compId]
				if hPtr == nil {
					ans = append(ans, -1)
				} else {
					for hPtr.Len() > 0 {
						candidate := (*hPtr)[0]
						candidateInt := int(candidate)
						if onlineArr[candidateInt] {
							ans = append(ans, candidate)
							break
						} else {
							heap.Pop(hPtr)
						}
					}
					if hPtr.Len() == 0 {
						ans = append(ans, -1)
					}
				}
			}
		} else if typ == 2 {
			onlineArr[xInt] = false
		}
	}

	return ans
}
```

### Explanation
1. **Graph Construction**: The graph is built using an adjacency list from the given connections.
2. **Component Identification**: BFS is used to traverse the graph and identify connected components. Each component is assigned a unique ID, and a min-heap is initialized for each component to store station IDs.
3. **Online Status Tracking**: An array `onlineArr` tracks the online status of each station, initialized to `true` for all stations.
4. **Query Handling**:
   - **Type 1 (Maintenance Check)**: If the station is online, its ID is returned. If offline, the min-heap of its component is used to find the smallest online station by repeatedly popping offline stations from the heap. If the heap is emptied, -1 is returned.
   - **Type 2 (Take Offline)**: The station's status is updated to offline in `onlineArr`. The min-heap remains unchanged until queried, when offline stations are removed during heap operations.

This approach efficiently handles queries by leveraging min-heaps to quickly access the smallest online station in any component, ensuring optimal performance even for large networks.

To solve this problem, we need to handle a series of queries on a power grid represented by a graph of interconnected stations. The queries involve checking the status of a station or turning a station offline, and for each check query, we need to return the smallest online station in the same connected component as the queried station.

### Approach
1. **Union-Find Data Structure (Disjoint Set Union - DSU):** 
   - We use this to efficiently manage and query the connected components of the graph. The DSU helps in identifying which component a station belongs to and merging components when connections are added.

2. **MinHeap for Each Component:**
   - Each connected component has a min-heap that stores all online stations in that component. This allows us to efficiently retrieve the smallest online station in logarithmic time.

3. **Handling Queries:**
   - **Type 1 (Check Station):** If the station is online, the result is the station itself. If offline, the result is the top of the min-heap for its component (smallest online station). If the heap is empty, return -1.
   - **Type 2 (Offline Station):** Mark the station as offline and remove it from the component's min-heap. The heap is adjusted to maintain its properties after removal.

4. **Preprocessing:**
   - **Connectivity Setup:** Use DSU to process all connections and determine connected components.
   - **Component Mapping:** For each station, store its root (component identifier).
   - **Heap Initialization:** For each component, initialize a min-heap with all stations in that component (all stations start online).

