        root := x
        for parent[root] != root {
            root = parent[root]
        }
        for parent[x] != root {
            next := parent[x]
            parent[x] = root
            x = next
        }
        return root
    }

    for _, conn := range connections {
        u := int(conn[0])
        v := int(conn[1])
        ru := find(u)
        rv := find(v)
        if ru == rv {
            continue
        }
        if rank[ru] < rank[rv] {
            parent[ru] = rv
        } else if rank[rv] < rank[ru] {
            parent[rv] = ru
        } else {
            parent[rv] = ru
            rank[ru]++
        }
    }

    rootForNode := make([]int, n+1)
    for i := 1; i <= n; i++ {
        rootForNode[i] = find(i)
    }

    compMap := make(map[int][]int)
    for i := 1; i <= n; i++ {
        root := rootForNode[i]
        compMap[root] = append(compMap[root], i)
    }

    for _, list := range compMap {
        sort.Ints(list)
    }

    online := make([]bool, n+1)
    for i := 1; i <= n; i++ {
        online[i] = true
    }

    headByRoot := make(map[int]*ListNode)
    nodePtr := make([]*ListNode, n+1)

    for root, list := range compMap {
        if len(list) == 0 {
            headByRoot[root] = nil
            continue
        }
        headNode := &ListNode{val: list[0]}
        nodePtr[list[0]] = headNode
        prevNode := headNode
        for i := 1; i < len(list); i++ {
            node := &ListNode{val: list[i]}
            nodePtr[list[i]] = node
            prevNode.next = node
            node.prev = prevNode
            prevNode = node
        }
        headByRoot[root] = headNode
    }

    results := []int64{}
    for _, q := range queries {
        t := q[0]
        x := int(q[1])
        if t == 1 {
            if online[x] {
                results = append(results, q[1])
            } else {
                root := rootForNode[x]
                headNode := headByRoot[root]
                if headNode == nil {
                    results = append(results, -1)
                } else {
                    results = append(results, int64(headNode.val))
                }
            }
        } else if t == 2 {
            if online[x] {
                online[x] = false
                root := rootForNode[x]
                node := nodePtr[x]
                if headByRoot[root] == node {
                    headByRoot[root] = node.next
                }
                if node.prev != nil {
                    node.prev.next = node.next
                }
                if node.next != nil {
                    node.next.prev = node.prev
                }
            }
        }
    }
    return results
}
