import (
	"container/heap"
)

type IntHeap []int

func (h IntHeap) Len() int           { return len(h) }
func (h IntHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h IntHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *IntHeap) Push(x interface{}) { *h = append(*h, x.(int)) }
func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	nNodes := int(c)
	parent := make([]int, nNodes+1)
	rank := make([]int, nNodes+1)
	for i := 1; i <= nNodes; i++ {
		parent[i] = i
	}

	var find func(int) int
	find = func(x int) int {
		if parent[x] != x {
			parent[x] = find(parent[x])
		}
		return parent[x]
	}

	union := func(a, b int) {
		a = find(a)
		b = find(b)
		if a == b {
			return
		}
		if rank[a] < rank[b] {
			parent[a] = b
		} else if rank[a] > rank[b] {
			parent[b] = a
		} else {
			parent[b] = a
			rank[a]++
		}
	}

	for _, conn := range connections {
		u := conn[0]
		v := conn[1]
		uu, vv := int(u), int(v)
		union(uu, vv)
	}

	root := make([]int, nNodes+1)
	components := make(map[int][]int)
	for i := 1; i <= nNodes; i++ {
		r := find(i)
		root[i] = r
		components[r] = append(components[r], i)
	}

	heapMap := make(map[int]*IntHeap)
	for r, nodes := range components {
		h := IntHeap(nodes)
		heap.Init(&h)
		heapMap[r] = &h
	}

	online := make([]bool, nNodes+1)
	for i := 1; i <= nNodes; i++ {
		online[i] = true
	}

	ans := []int64{}
	for _, q := range queries {
		t := q[0]
		x := int(q[1])
		if t == 1 {
			if online[x] {
				ans = append(ans, int64(x))
			} else {
				r := root[x]
				hPtr, exists := heapMap[r]
				if !exists {
					ans = append(ans, -1)
				} else {
					res := int64(-1)
					h := *hPtr
					for h.Len() > 0 {
						minVal := h[0]
						if online[minVal] {
							res = int64(minVal)
							break
						} else {
							heap.Pop(&h)
						}
					}
					if res != -1 {
						ans = append(ans, res)
					} else {
						ans = append(ans, -1)
					}
					heapMap[r] = &h
				}
			}
		} else if t == 2 {
			online[x] = false
		}
	}
	return ans
}
